import React from "react";

export default function Header({
  query,
  setQuery,
  category,
  setCategory,
  filters,
  setFilters,
  filteredCount,
  isMobile,
  searchOpen,
  setSearchOpen,
  openPanel,
  setOpenPanel,
  onLogoClick,
  onContactClick,
}) {
  return (
    <div
      style={{
        background: "#fff",
        padding: "12px 20px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        position: "relative",
        zIndex: 100,
        fontFamily: "'Montserrat', sans-serif",
      }}
    >
      {/* LOGO */}
      <img
        src="/logo.png"
        alt="Marist-Art"
        style={{
          height: "40px",
          cursor: "pointer",
          opacity: 0.9,
        }}
        onClick={onLogoClick}
      />

      {/* CENTRO: menú escritorio o hamburguesa */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "16px",
          flex: 1,
          justifyContent: "center",
        }}
      >
        {!isMobile ? (
          <>
            {[
              { key: "todas", label: "Todas" },
              { key: "ilustracion", label: "Ilustración" },
              { key: "diseno", label: "Diseño" },
            ].map((cat) => {
              const active = category === cat.key;
              return (
                <span
                  key={cat.key}
                  onClick={() => {
                    setQuery("");
                    setFilters([]);
                    setCategory(cat.key);
                  }}
                  style={{
                    cursor: "pointer",
                    color: active ? "#111" : "#aaa",
                    fontWeight: active ? "600" : "400",
                    fontSize: "13px",
                    fontStyle: "italic",
                  }}
                >
                  {cat.label}
                </span>
              );
            })}

            <span
              onClick={onContactClick}
              style={{
                cursor: "pointer",
                color: "#aaa",
                fontSize: "13px",
                fontStyle: "italic",
              }}
            >
              Contacto
            </span>
          </>
        ) : (
          <>
            <button
              onClick={() =>
                setOpenPanel(openPanel === "menu" ? null : "menu")
              }
              style={{
                border: "none",
                background: "transparent",
                fontSize: "20px",
                cursor: "pointer",
              }}
            >
              ☰
            </button>

            {/* DESPLEGABLE MÓVIL */}
            {openPanel === "menu" && (
              <div
                style={{
                  position: "absolute",
                  top: "100%",
                  left: 0,
                  right: 0,
                  background: "#fff",
                  borderBottom: "1px solid #eee",
                  padding: "16px 20px",
                  display: "flex",
                  flexDirection: "column",
                  gap: "12px",
                  zIndex: 99,
                  boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
                }}
              >
                {[
                  { key: "todas", label: "Todas" },
                  { key: "ilustracion", label: "Ilustración" },
                  { key: "diseno", label: "Diseño" },
                ].map((cat) => {
                  const active = category === cat.key;
                  return (
                    <span
                      key={cat.key}
                      onClick={() => {
                        setQuery("");
                        setFilters([]);
                        setCategory(cat.key);
                        setOpenPanel(null);
                      }}
                      style={{
                        cursor: "pointer",
                        color: active ? "#111" : "#555",
                        fontWeight: active ? "600" : "400",
                        fontSize: "16px",
                        fontStyle: "italic",
                        padding: "8px 0",
                        borderBottom: "1px solid #f0f0f0",
                      }}
                    >
                      {cat.label}
                    </span>
                  );
                })}

                <span
                  onClick={() => {
                    onContactClick();
                    setOpenPanel(null);
                  }}
                  style={{
                    cursor: "pointer",
                    color: "#555",
                    fontSize: "16px",
                    fontStyle: "italic",
                    padding: "8px 0",
                  }}
                >
                  Contacto
                </span>
              </div>
            )}
          </>
        )}
      </div>

      {/* DERECHA: resultados + buscador */}
      <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
        {!isMobile && (
          <span
            style={{
              fontSize: "12px",
              color: "#888",
              fontStyle: "italic",
            }}
          >
            {filteredCount} results
          </span>
        )}

        {/* BUSCADOR CON EXPANSIÓN */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            border: "1px solid rgba(120,80,200,0.5)",
            borderRadius: "999px",
            padding: "6px 12px",
            background: "#fff",
            width: searchOpen ? "220px" : "40px",
            transition: "width 0.25s ease",
            overflow: "hidden",
          }}
        >
          <span
            onClick={() => setSearchOpen(!searchOpen)}
            style={{ color: "#aaa", cursor: "pointer", flexShrink: 0 }}
          >
            🔍
          </span>

          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => setSearchOpen(true)}
            placeholder="Buscar"
            aria-label="Buscar ilustraciones"
            style={{
              border: "none",
              outline: "none",
              fontSize: "13px",
              width: "100%",
              background: "transparent",
              color: "#555",
              fontFamily: "'Montserrat', sans-serif",
            }}
          />

          {query && (
            <span
              onClick={(e) => {
                e.preventDefault();
                setQuery("");
              }}
              onMouseDown={(e) => e.preventDefault()}
              role="button"
              aria-label="Borrar búsqueda"
              style={{
                cursor: "pointer",
                color: "#aaa",
                fontSize: "14px",
                padding: "0 4px",
                userSelect: "none",
                flexShrink: 0,
              }}
            >
              ✕
            </span>
          )}
        </div>
      </div>
    </div>
  );
}
